script:
frappe.ui.form.on('Daftra Settings', {
    refresh: function(frm) {
        // Show module status
        var modules = [
            'Sales', 'Clients', 'Inventory', 'Purchases', 
            'Accounting', 'HR', 'POS', 'Bookings', 
            'Time Tracking', 'Tax'
        ];
        modules.forEach(function(mod) {
            var field = 'enable_' + mod.toLowerCase() + '_module';
            var enabled = frm.doc[field];
            frm.set_df_property(field, 'description', 
                enabled ? 'Module is ACTIVE' : 'Module is DISABLED');
        });
    }
});
